from priorityQueue import PriorityQueue
import math


def a_star(graph, start, goal, heuristic):
    '''
    A* shortest-path search on a weighted graph with non-negative edge
    weights and an admissible heuristic.

    Inputs:
    [graph]: adjacency mapping of the form {node: {neighbor: weight}}
             with numeric, non-negative weights.
    [start]: the source node.
    [goal]: the target node.
    [heuristic]: callable taking a node and returning a numeric estimate
                 of the remaining distance to [goal]. Must be admissible
                 (never overestimates) for optimality.

    Outputs:
    [path]: list of nodes from [start] to [goal] forming a shortest path,
            or None if [goal] is unreachable from [start].
    [length]: total length of the returned path, or math.inf if [goal]
              is unreachable.
    '''

    g_score = {start: 0}
    predecessor = {start: None}
    open_set = PriorityQueue()
    open_set.add(start, heuristic(start))
    closed = set()

    while True:
        try:
            current = open_set.pop()
        except KeyError:
            # open set exhausted without reaching goal
            return None, math.inf

        if current == goal:
            path = []
            node = goal
            while node is not None:
                path.insert(0, node)
                node = predecessor[node]
            return path, g_score[goal]

        closed.add(current)

        for neighbor, weight in graph.get(current, {}).items():
            if neighbor in closed:
                continue
            tentative_g = g_score[current] + weight
            if tentative_g < g_score.get(neighbor, math.inf):
                # relaxation step
                g_score[neighbor] = tentative_g
                predecessor[neighbor] = current
                # f = g + h; PriorityQueue.add updates priority if present
                open_set.add(neighbor, tentative_g + heuristic(neighbor))


if __name__ == '__main__':

    # Grid-style example with Manhattan-distance heuristic.
    # Nodes are (row, col) tuples; edges connect 4-neighbors with weight 1.
    coords = {(r, c) for r in range(4) for c in range(4)}
    blocked = {(1, 1), (1, 2), (2, 2)}
    nodes = coords - blocked

    grid = {n: {} for n in nodes}
    for (r, c) in nodes:
        for (dr, dc) in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            neighbor = (r + dr, c + dc)
            if neighbor in nodes:
                grid[(r, c)][neighbor] = 1

    start = (0, 0)
    goal = (3, 3)

    def manhattan(node):
        return abs(node[0] - goal[0]) + abs(node[1] - goal[1])

    path, length = a_star(grid, start, goal, manhattan)
    print('Shortest path from ' + str(start) + ' to ' + str(goal) + ':')
    print(path)
    print('Length: ' + str(length))

